import osn = 4  # rank numberskiplines = 3pdb_folder = "PDB"merge_folder = os.path.join(pdb_folder, "mergePDB")if not os.path.exists(merge_folder):    os.makedirs(merge_folder)    pdb_filenames = [filename for filename in os.listdir(pdb_folder)                  if filename.endswith(".pdb")]timeframes = sorted(set([int(filename.split("_")[1].split(".")[0])                          for filename in pdb_filenames]))for timeframe in timeframes:    merged_filename = f"{timeframe}.pdb"    merged_path = os.path.join(merge_folder, merged_filename)        with open(merged_path, "w") as merged_file:        for rank in range(n):            input_filename = f"{rank}_{timeframe}.pdb"            input_path = os.path.join(pdb_folder, input_filename)                        with open(input_path, "r") as input_file:                if rank == 0:                    merged_file.write(input_file.read())                else:                    for _ in range(skiplines):                        input_file.readline()                    merged_file.write(input_file.read())                    